import osfrom ament_index_python.packages import get_package_share_directoryfrom launch import LaunchDescriptionfrom launch.actions import DeclareLaunchArgument, IncludeLaunchDescription, RegisterEventHandler, ExecuteProcessfrom launch.event_handlers import OnProcessExitfrom launch.launch_description_sources import PythonLaunchDescriptionSourcefrom launch.substitutions import Command, LaunchConfigurationfrom launch_ros.actions import Nodefrom launch_ros.parameter_descriptions import ParameterValuedef generate_launch_description():    pkg_share = get_package_share_directory('ur16')        # Gazebo'nun kendi ROS paketini bul    gazebo_ros_pkg = get_package_share_directory('gazebo_ros')    # XACRO dosyamızın yolu    # DİKKAT: 'ur16.urdf.xacro' dosyasını oluşturduğunu varsayıyorum!    xacro_file = os.path.join(pkg_share, 'urdf', 'ur16.urdf.xacro')    # 1. Robot State Publisher (XACRO'yu işleyip yayınlar)    robot_description = ParameterValue(Command(['xacro ', xacro_file]), value_type=str)        node_robot_state_publisher = Node(        package='robot_state_publisher',        executable='robot_state_publisher',        output='screen',        parameters=[{'robot_description': robot_description}]    )    # 2. Gazebo'yu Başlat (Boş bir dünya ile)    gazebo = IncludeLaunchDescription(        PythonLaunchDescriptionSource(            os.path.join(gazebo_ros_pkg, 'launch', 'gazebo.launch.py')        ),    )    # 3. Robotu Gazebo'ya "Spawn" Et (Yerleştir)    spawn_entity = Node(        package='gazebo_ros',        executable='spawn_entity.py',        arguments=['-topic', 'robot_description', '-entity', 'ur16_robot'],        output='screen'    )    # 4. Kontrolcüleri Yükle (Sırayla)        # Önce Joint State Broadcaster'ı yükle    load_joint_state_broadcaster = Node(        package="controller_manager",        executable="spawner",        arguments=["joint_state_broadcaster"],        output="screen",    )    # Sonra Trajectory Controller'ı yükle    load_joint_trajectory_controller = Node(        package="controller_manager",        executable="spawner",        arguments=["joint_trajectory_controller"],        output="screen",    )    return LaunchDescription([        gazebo,        node_robot_state_publisher,        spawn_entity,        load_joint_state_broadcaster,        load_joint_trajectory_controller    ])